# Module defining geometric shapes with inheritance and interfaces

interface IDrawable:
    def draw(self) -> str: ...

class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle {self.name}: {self.width} x {self.height}"

class Circle(Shape):
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle {self.name}: radius={self.radius}"

class DrawableRectangle(Rectangle, IDrawable):
    def __init__(self, name: str, width: float, height: float):
        super().__init__(name, width, height)

    def draw(self) -> str:
        return f"Drawing rectangle {self.name}"

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

def create_shape_collection() -> list[Shape]:
    shapes: list[Shape] = []
    shapes.append(Rectangle("R1", 5.0, 3.0))
    shapes.append(Circle("C1", 2.0))
    shapes.append(Rectangle("R2", 4.0, 4.0))
    return shapes
